svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🔍 SVG WITH IFRAME TEST');
console.log('═══════════════════════════════════════');

console.log('✅ SVG loaded successfully');
console.log('📍 Attempting to load iframe to: https://ai.planet.com');

// Wait for DOM to be ready
window.addEventListener('load', function() {
  console.log('📌 Window load event fired');

  // Method 1: Using foreignObject (recommended for SVG)
  try {
    var fo = document.querySelector('foreignObject');
    if (fo) {
      console.log('  ✅ foreignObject found');
      var div = fo.querySelector('div');
      if (div) {
        console.log('  ✅ div container found');
        var iframe = div.querySelector('iframe');
        if (iframe) {
          console.log('  ✅ iframe element found');
          console.log('  📍 iframe src:', iframe.src);

          // Add load event listener
          iframe.onload = function() {
            console.log('  ✅ IFRAME LOADED SUCCESSFULLY!');
            console.log('  📍 iframe URL:', iframe.src);

            try {
              console.log('  📍 iframe contentWindow:', iframe.contentWindow);
              if (iframe.contentWindow) {
                console.log('  📍 contentWindow.location:', iframe.contentWindow.location.href);
              }
            } catch(e) {
              console.warn('  ⚠️ Cannot access contentWindow (CORS):', e.message);
            }
          };

          iframe.onerror = function(e) {
            console.error('  ❌ iframe error:', e);
          };
        }
      }
    }
  } catch(e) {
    console.error('  ❌ ForeignObject method failed:', e.message);
  }

  // Method 2: Alternative - create iframe dynamically (using createElementNS for SVG)
  try {
    // Create foreignObject dynamically
    var newFo = document.createElementNS('http://www.w3.org/2000/svg', 'foreignObject');
    newFo.setAttribute('x', '20');
    newFo.setAttribute('y', '60');
    newFo.setAttribute('width', '760');
    newFo.setAttribute('height', '520');

    var newDiv = document.createElement('div');
    newDiv.setAttribute('xmlns', 'http://www.w3.org/1999/xhtml');
    newDiv.style.width = '100%';
    newDiv.style.height = '100%';

    var newIframe = document.createElement('iframe');
    newIframe.src = 'https://ai.planet.com';
    newIframe.style.width = '100%';
    newIframe.style.height = '100%';
    newIframe.style.border = '1px solid #ccc';
    newIframe.style.borderRadius = '5px';
    newIframe.setAttribute('sandbox', 'allow-scripts allow-same-origin allow-forms');

    newDiv.appendChild(newIframe);
    newFo.appendChild(newDiv);
    document.documentElement.appendChild(newFo);

    console.log('  ✅ Dynamically created iframe (alternative method)');
    console.log('  📍 New iframe src:', newIframe.src);

    newIframe.onload = function() {
      console.log('  ✅ DYNAMIC IFRAME LOADED!');
    };

  } catch(e) {
    console.error('  ❌ Dynamic creation failed:', e.message);
  }

  console.log('\n⏱️ Test completed at:', new Date().toISOString());
  console.log('═══════════════════════════════════════');
});

// Initial log
console.log('📌 Script execution started');
console.log('📍 SVG readyState:', document.readyState);
